import{_ as i,o as s,c as a,ag as e}from"./chunks/framework.BuUvxvtQ.js";const p="/assets/git-github.Bh_Av3lU.png",o="/assets/GayHub.Dzjntus2.png",l="/assets/Github%E5%88%9B%E5%BB%BA%E4%BB%93%E5%BA%93.CAPP239N.png",n="/assets/%E5%88%9B%E5%BB%BA%E4%BB%93%E5%BA%932.BBr63KXQ.png",r="/assets/%E5%88%9B%E5%BB%BA%E4%BB%93%E5%BA%933.CSTSktOt.png",h="/assets/%E4%BB%93%E5%BA%93%E6%93%8D%E4%BD%9C.QI-VRQ6t.png",c="/assets/%E5%88%A0%E9%99%A4%E4%BB%93%E5%BA%93.BNZF4IT-.png",d="/assets/%E5%88%A0%E9%99%A4%E4%BB%93%E5%BA%931.BUOuZ3Ey.png",A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"团队开发/GitHub.md","filePath":"团队开发/GitHub.md","lastUpdated":1775898880000}'),g={name:"团队开发/GitHub.md"};function u(B,t,b,k,_,E){return s(),a("div",null,[...t[0]||(t[0]=[e('<h3 id="what-s-github" tabindex="-1">What&#39;s GitHub? <a class="header-anchor" href="#what-s-github" aria-label="Permalink to &quot;What&#39;s  GitHub?&quot;">​</a></h3><p><img src="'+p+'" alt="git-github"></p><p>我们知道Git作为版本控制程序能够创建本地仓库并连接远程仓库，本地仓库在我们的个人电脑上，而远程仓库就托管在GitHub上。GitHub是全球最大的开源代码托管平台，在平台上创建开源仓库完全免费，上面有着来自全球优秀程序员的开源项目，是互联网精神的具象化的产物。作为全球最大的程序员社交平台，它于2018年被微软收购，如果硬要说缺点的话那就是全英文对英语不好的同学不太友好，同时国内需要科学上网才能稳定访问。</p><p>题外话：是GitHub不是GayHub！😤</p><p><img src="'+o+'" alt="GayHub"></p><h3 id="关于仓库" tabindex="-1">关于仓库 <a class="header-anchor" href="#关于仓库" aria-label="Permalink to &quot;关于仓库&quot;">​</a></h3><p>Github上的代码是以仓库的形式托管的，当你需要托管一个项目的代码时就可以为这个项目创建一个仓库，并将项目的所有代码存放在仓库当中，这个仓库可以是私人的（尽自己组织可见），也可以是公开的，</p><h4 id="创建仓库" tabindex="-1">创建仓库： <a class="header-anchor" href="#创建仓库" aria-label="Permalink to &quot;创建仓库：&quot;">​</a></h4><p>在GitHub上即使你是游客的身份访问也能无障碍的下载或是拉取开源项目，但是如果你想要创建自己的远程仓库就需要注册一个GitHub账号，这里就不再讲述如何注册，直奔如何创建仓库。</p><p>在<code>Home</code>页面下，点击右上方的<code>+</code>可以选者创建新仓库或者导入本地仓库</p><p><img src="'+l+'" alt="Github创建仓库"></p><p>点击创建新仓库就会来到下面的页面，在这个页面里你可以选择创建的仓库的名称，是否公开和是否在初始化时添加<code>README</code>文件</p><p><img src="'+n+'" alt="创建仓库2"></p><p>这里主要解释以下最后两个选项</p><p><strong>Add <code>.gitignore</code></strong></p><p><code>.gitignore</code>文件用于指定在Git版本控制中应该被忽略的文件和目录。这些通常是一些不需要被跟踪的文件，例如：</p><ul><li><strong>编译产生的文件</strong>：如中间文件、二进制文件。</li><li><strong>操作系统特有的文件</strong>：如Thumbs.db（Windows）或.DS_Store（macOS）。</li><li><strong>环境配置文件</strong>：如包含敏感信息的配置文件，通常希望保留在本地而不推送到远程。</li></ul><p>通过添加<code>.gitignore</code>，可以保持代码库的整洁，提高代码管理的效率。</p><p><strong>Choose a License</strong></p><p>选择许可证是指你决定如何允许他人使用、复制、修改和分发你的代码。不同的许可证提供不同的权利和限制，常见的许可证包括：</p><ul><li><strong>MIT许可证</strong>：非常宽松，允许任何人使用、复制、修改，只需保留原许可证说明。</li><li><strong>Apache 2.0许可证</strong>：提供专利权利，适合需要保护专利的项目。</li><li><strong>GPL许可证（通用公共许可证）</strong>：要求任何修改和再发布的代码也必须采用相同许可证，适合倡导开源的软件。</li></ul><p>点击<code>Creat reposity</code>即可创建自己的远程仓库，然后复制远程仓库的地址</p><p><img src="'+r+'" alt="创建仓库3"></p><p>在本地仓库中打开<code>git</code>执行下面命令：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">websit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #这里&lt;website&gt;填你远程仓库的地址</span></span></code></pre></div><p>这样你的远程仓库就创建完毕了</p><h4 id="仓库操作" tabindex="-1">仓库操作： <a class="header-anchor" href="#仓库操作" aria-label="Permalink to &quot;仓库操作：&quot;">​</a></h4><p>当你的仓库创建成功之后，点击仓库你会看到如下界面：</p><p><img src="'+h+'" alt="仓库操作"></p><p>我将主要介绍图中箭头所指位置的常用功能：</p><ol><li>在1所指位置可以查看当前仓库所在分支，点击可以切换到其他分支</li><li>在2所指位置可以复制当前仓库的网址，或者下载当前仓库内容的压缩包</li><li>在3所指位置是对当前仓库的情况的概述</li><li>在4所指位置是当前仓库发行的程序和包</li><li>在5所指位置可以查看历史提交记录</li></ol><p>PS.</p><ul><li>release 通常是一个整体的版本发布，包含的更改和更新详细，你需要下载开源程序往往就在这里。</li><li>Package 则是单个代码或组件的版本，可以被其他项目直接引用或使用。</li></ul><h4 id="仓库删除" tabindex="-1">仓库删除： <a class="header-anchor" href="#仓库删除" aria-label="Permalink to &quot;仓库删除：&quot;">​</a></h4><p><img src="'+c+'" alt="删除仓库"></p><p>在仓库页面中选择<code>Setting</code>，然后拉到最下方红色框住的部分就是删除仓库的部分</p><p><img src="'+d+'" alt="删除仓库1"></p><p>如果你要删除仓库平台会让你再三确认，因为这是一件十分危险的事情，如果不这样做可能一不注意很多人的心血就付之东流了。</p>',38)])])}const G=i(g,[["render",u]]);export{A as __pageData,G as default};
